const target = document.querySelector('[data-scroll="edit-form"]');
if (!target) return;

const rect = target.getBoundingClientRect();
const alreadyFullyVisible = rect.top >= 0 && rect.bottom <= window.innerHeight;

if (!alreadyFullyVisible && document.body.scrollHeight > window.innerHeight) {
  target.scrollIntoView({
    behavior: 'smooth',
    block: 'start'
  });
}

